"use client"

import React, { useEffect, useState } from 'react'
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from "@/components/ui/dialog"
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from "@/components/ui/card"
import { Target, Flame, Plus, Trash2, Moon, Sun, CalendarDays, LogOut, CheckCircle2, LayoutDashboard, Brain, Activity, Sparkles, Loader2, Leaf, Coffee, Smile, Clock } from "lucide-react"
import { useTheme } from "next-themes"
import { motion, AnimatePresence } from "framer-motion"
import type { Variants } from "framer-motion"

import FullCalendar from '@fullcalendar/react'
import dayGridPlugin from '@fullcalendar/daygrid'
import interactionPlugin from '@fullcalendar/interaction'

import { useStore } from "@/store/useStore"
import { format } from 'date-fns'
import { HabitHeatmap } from '@/components/HabitHeatmap'
import { AuthScreen } from '@/components/AuthScreen'
import { AnalyticsDashboard } from '@/components/AnalyticsDashboard'
import { GlobalHeatmap } from '@/components/GlobalHeatmap'
import { MoodHeatmap } from '@/components/MoodHeatmap'
import { EventHeatmap } from '@/components/EventHeatmap'
import { MoodSelector } from '@/components/MoodSelector'
import { BrainDump } from '@/components/BrainDump'
import { DashboardSkeleton } from '@/components/DashboardSkeleton'
import confetti from 'canvas-confetti'

// Variantes de animación
const containerVariants: Variants = {
  hidden: { opacity: 0 },
  show: { opacity: 1, transition: { staggerChildren: 0.1 } }
};
const itemVariants: Variants = {
  hidden: { y: 20, opacity: 0 },
  show: { y: 0, opacity: 1, transition: { type: "spring" as const, bounce: 0.4 } }
};

type TabId = 'home' | 'habits' | 'brain' | 'analytics';

/**
 * PALETA HIGH-CONTRAST MOSS (V5.2)
 * - Background: Lino Profundo (#e9e0d8) -> Más contraste con tarjetas
 * - Cards: Blanco Puro (#ffffff)
 * - Primary: Verde Musgo Profundo (#3a5a40)
 * - Accent: Barro (#a47148)
 * - Text: Bosque Negro (#283618)
 */

export default function Home() {
  const { 
    user, checkUser, signOut, isCheckingSession,
    events, habits, habitLogs, isLoading, fetchData, 
    addEvent, deleteEvent, addHabit, deleteHabit, toggleHabitLog 
  } = useStore();

  const { theme, setTheme } = useTheme();
  const [activeTab, setActiveTab] = useState<TabId>('home');

  // Form states
  const [newHabit, setNewHabit] = useState("");
  const [newHabitDesc, setNewHabitDesc] = useState("");
  const [newHabitIcon, setNewHabitIcon] = useState("🌿");
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [selectedDateStr, setSelectedDateStr] = useState("");
  const [newEventTitle, setNewEventTitle] = useState("");

  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
    checkUser();
  }, [checkUser]);

  const handleAddHabit = async () => {
    if (newHabit.trim() === "") return;
    await addHabit({ name: newHabit, description: newHabitDesc, icon: newHabitIcon });
    setNewHabit("");
    setNewHabitDesc("");
    setNewHabitIcon("🌿");
  };

  const handleDateClick = (arg: any) => {
    setSelectedDateStr(arg.dateStr);
    setNewEventTitle("");
    setIsDialogOpen(true);
  };

  const handleSaveEvent = async () => {
    if (newEventTitle.trim() === "") return;
    await addEvent({
      title: newEventTitle,
      date: selectedDateStr,
      all_day: true
    });
    setIsDialogOpen(false);
  };

  const handleEventClick = async (arg: any) => {
    if(confirm(`¿Deseas eliminar la tarea "${arg.event.title}"?`)) {
      await deleteEvent(arg.event.id);
    }
  };

  const todayStr = React.useMemo(() => format(new Date(), 'yyyy-MM-dd'), []);

  const triggerConfettiAndToggle = async (habitId: string, currentlyCompleted: boolean) => {
    await toggleHabitLog(habitId, todayStr);
    if (!currentlyCompleted) {
      confetti({
        particleCount: 200,
        spread: 90,
        origin: { y: 0.75 },
        colors: ['#3a5a40', '#588157', '#a47148', '#ffffff'],
        gravity: 0.8
      });
    }
  };

  const enrichedHabits = React.useMemo(() => {
    return habits.map(habit => {
      const logs = habitLogs.filter(log => log.habit_id === habit.id);
      const isCompletedToday = logs.some(log => log.completed_date === todayStr);
      const streak = logs.length;
      return { ...habit, logs, isCompletedToday, streak };
    });
  }, [habits, habitLogs, todayStr]);

  const completedTodayCount = enrichedHabits.filter(h => h.isCompletedToday).length;
  const totalHabits = enrichedHabits.length;

  const tabs = [
    { id: 'home', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'habits', label: 'Hábitos', icon: Leaf },
    { id: 'brain', label: 'Brain Dump', icon: Brain },
    { id: 'analytics', label: 'Estadísticas', icon: Activity },
  ] as const;

  if (!isMounted || (isCheckingSession && !user)) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#e9e0d8] dark:bg-[#0a0f0a]">
         <div className="flex flex-col items-center gap-4">
            <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }}>
               <Loader2 className="w-10 h-10 text-[#3a5a40]" />
            </motion.div>
         </div>
      </div>
    );
  }

  if (!user) return <AuthScreen />;
  return (
    <main className="min-h-screen bg-[#e9e0d8] dark:bg-[#0a0f0a] text-[#283618] dark:text-[#dad7cd] font-sans selection:bg-[#31572c]/40 transition-colors duration-500 overflow-x-hidden pb-24 relative px-2 sm:px-0">

      <header className="sticky top-0 z-50 w-full border-b border-[#3a5a40]/20 dark:border-[#3a5a40]/30 bg-white/95 dark:bg-[#1b221b]/98 backdrop-blur-md px-4 sm:px-8 py-5 shadow-2xl shadow-[#344e41]/10 transition-colors">
        <div className="max-w-[1600px] mx-auto flex flex-col sm:flex-row items-center justify-between gap-4">

          <div className="flex items-center gap-4">
             <div className="w-12 h-12 flex items-center justify-center rounded-[1.2rem] bg-[#3a5a40] shadow-2xl text-white">
               <Leaf className="w-6 h-6" />
             </div>
             <h1 className="font-extrabold text-2xl tracking-tighter text-[#344e41] dark:text-[#dad7cd] leading-none uppercase">Dashboard</h1>
          </div>

          <nav className="flex items-center bg-[#dad7cd]/50 dark:bg-black/60 p-1.5 rounded-[2.5rem] border border-[#344e41]/10 backdrop-blur-md">
             {tabs.map((tab) => {
               const Icon = tab.icon;
               const isActive = activeTab === tab.id;
               return (
                 <button key={tab.id} onClick={() => setActiveTab(tab.id as TabId)} className={`relative flex items-center gap-3 px-8 py-3.5 rounded-[2rem] text-sm font-black transition-all ${isActive ? 'text-white dark:text-[#a3b18a] z-10' : 'text-[#3a5a40] dark:text-[#588157] hover:text-[#344e41] dark:hover:text-[#dad7cd]'}`}>
                   {isActive && ( <motion.div layoutId="activeTab" className="absolute inset-0 bg-[#3a5a40] dark:bg-[#344e41] shadow-2xl rounded-[2rem]" transition={{ type: "spring", bounce: 0.1, duration: 0.7 }} /> )}
                   <Icon className={`w-4 h-4 relative z-10 ${isActive ? 'scale-110' : ''}`} />
                   <span className="relative z-10 hidden md:inline">{tab.label}</span>
                 </button>
               )
             })}
          </nav>

          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="rounded-full hover:bg-[#dad7cd]/40 text-[#3a5a40]">
              <Sun className="h-5 w-5 rotate-0 scale-100 transition-all dark:-rotate-90 dark:scale-0" />
              <Moon className="absolute h-5 w-5 rotate-90 scale-0 transition-all dark:rotate-0 dark:scale-100" />
            </Button>
            <Button variant="ghost" size="icon" onClick={() => signOut()} className="rounded-full text-red-600 hover:bg-red-50"> <LogOut className="h-5 w-5" /> </Button>
          </div>
        </div>
      </header>

      <motion.div variants={containerVariants} initial="hidden" animate="show" className="max-w-[1600px] mx-auto flex flex-col gap-12 mt-12 px-4 sm:px-8 relative z-10 w-full mb-12">

        <AnimatePresence mode="wait">
          {isLoading ? (
            <motion.div key="skeleton" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
               <DashboardSkeleton view={activeTab} />
            </motion.div>
          ) : (
            <motion.div 
              key={activeTab} 
              variants={containerVariants}
              initial="hidden" 
              animate="show" 
              exit={{ opacity: 0, x: -20 }} 
              transition={{ duration: 0.3 }} 
              className="w-full"
            >

              {/* DASHBOARD: CALENDARIO */}
              {activeTab === 'home' && (
                 <div className="flex flex-col gap-12 w-full">
                    <div className="flex items-center justify-between">
                       <h2 className="text-5xl font-black text-[#283618] dark:text-[#fefae0] tracking-tighter uppercase">Calendario</h2>
                       <div className="flex items-center gap-3 px-6 py-3 bg-white dark:bg-[#1b221b] rounded-[1.5rem] border border-[#a47148]/30 dark:border-[#3a5a40]/30 shadow-xl text-[11px] font-black uppercase text-[#344e41] tracking-widest">
                          <Clock className="w-5 h-5 text-[#a47148]" /> {format(new Date(), 'EEEE, d MMM')}
                       </div>
                    </div>
                    <Card className="card-base p-5 sm:p-12 overflow-hidden border-2">
                      <CardContent className="p-0">
                         <FullCalendar 
                            plugins={[dayGridPlugin, interactionPlugin]} 
                            initialView="dayGridMonth" 
                            events={events} 
                            dateClick={handleDateClick} 
                            eventClick={handleEventClick} 
                            headerToolbar={{ left: 'prev,next today', center: 'title', right: 'dayGridMonth' }} 
                            contentHeight="auto" 
                            aspectRatio={2.2}
                            firstDay={1}
                         />
                      </CardContent>
                    </Card>

                    <div className="pt-8">
                       <h3 className="text-3xl font-black text-[#344e41] dark:text-[#dad7cd] mb-10 tracking-tighter flex items-center gap-3 uppercase">
                          <Plus className="w-8 h-8 text-[#a47148] rotate-45" /> Historial de Compromisos
                       </h3>
                       <EventHeatmap />
                    </div>
                 </div>
              )}

              {/* HABITS: CENTRO DE GESTIÓN */}
              {activeTab === 'habits' && (
                 <div className="flex flex-col gap-10">

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-stretch">
                       {/* CREAR HÁBITO */}
                       <Card className="card-accent flex flex-col justify-center border-t-[8px]">
                          <div className="space-y-6 w-full">
                             <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-4 text-[#3a5a40] font-black text-3xl tracking-tighter uppercase leading-none">
                                   <Plus className="w-10 h-10 bg-[#3a5a40]/15 rounded-[1.2rem] p-2 text-[#3a5a40]" /> Nuevo Hábito
                                </div>
                             </div>
                             <div className="p-3 bg-[#dad7cd]/20 dark:bg-black/20 rounded-[1.5rem] border border-[#3a5a40]/10 flex items-center justify-between overflow-x-auto gap-2">
                                {["🌿", "💧", "🏃", "📚", "🧘", "💪", "🍎"].map(emoji => (
                                   <button 
                                      key={emoji} 
                                      onClick={() => setNewHabitIcon(emoji)} 
                                      className={`text-2xl p-2 rounded-xl transition-all flex-shrink-0 ${newHabitIcon === emoji ? 'bg-[#3a5a40] shadow-md scale-110' : 'hover:bg-[#dad7cd]/40 dark:hover:bg-[#3a5a40]/30 opacity-60 hover:opacity-100'}`}
                                   >
                                      {emoji}
                                   </button>
                                ))}
                             </div>
                             <Input 
                                placeholder="Ej. Meditación matutina" 
                                value={newHabit} 
                                onChange={(e) => setNewHabit(e.target.value)} 
                                className="input-base" 
                                onKeyDown={(e) => e.key === 'Enter' && handleAddHabit()}
                             />
                             <Button onClick={handleAddHabit} className="btn-primary w-full shadow-lg shadow-[#3a5a40]/20"> 
                                <Sparkles className="w-5 h-5" /> Sembrar Hábito 
                             </Button>
                          </div>
                       </Card>

                       {/* MOOD TRACKER */}
                       <MoodSelector />
                    </div>

                    <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 py-8 border-b-4 border-[#3a5a40]/10 dark:border-[#3a5a40]/20">
                       <h2 className="text-5xl font-black text-[#283618] dark:text-[#fefae0] tracking-tighter uppercase relative">
                          Hábitos Diarios
                       </h2>
                       <div className="flex items-center gap-3 px-6 py-3 bg-[#3a5a40]/5 rounded-[1.5rem] border border-[#3a5a40]/10 text-sm font-black uppercase text-[#344e41] dark:text-[#a3b18a] tracking-widest">
                          <Target className="w-5 h-5 text-[#3a5a40]" /> {completedTodayCount} / {totalHabits} COMPLETADOS
                       </div>
                    </div>

                    {enrichedHabits.length === 0 ? (
                       <div className="flex flex-col items-center justify-center p-16 text-center border-4 border-dashed border-[#3a5a40]/20 rounded-[3rem] bg-[#3a5a40]/5">
                          <div className="w-24 h-24 bg-[#3a5a40]/10 rounded-full flex items-center justify-center mb-6">
                             <Leaf className="w-12 h-12 text-[#3a5a40]" />
                          </div>
                          <h3 className="text-3xl font-black text-[#283618] dark:text-[#dad7cd] mb-4 uppercase tracking-tighter">Tu Jardín está Vacío</h3>
                          <p className="text-xl text-[#344e41]/70 dark:text-[#a3b18a] max-w-md font-bold text-balance">Comienza a cultivar tu mejor versión creando tu primer hábito arriba.</p>
                       </div>
                    ) : (
                       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                          {enrichedHabits.map((habit) => (
                            <motion.div key={habit.id} variants={itemVariants} drag="x" dragConstraints={{ left: 0, right: 0 }} dragElastic={0.2} onDragEnd={(e, info) => { if (info.offset.x > 80) triggerConfettiAndToggle(habit.id, habit.isCompletedToday) }} className="h-full cursor-grab active:cursor-grabbing group relative">
                              <Card className={`card-base border-2 hover:border-[#3a5a40]/40 overflow-hidden active:scale-[0.98] p-0 transition-all duration-500 ease-out ${habit.isCompletedToday ? 'bg-gradient-to-br from-[#3a5a40]/10 to-transparent border-[#3a5a40]/30 shadow-inner' : 'bg-white dark:bg-[#1b221b] shadow-xl hover:shadow-2xl'}`}>
                                <CardContent className="p-0 flex flex-col h-full justify-between gap-6 relative">

                                  {habit.isCompletedToday && (
                                     <div className="absolute inset-0 bg-[#3a5a40]/5 mix-blend-multiply pointer-events-none" />
                                  )}

                                  <div className="flex items-start justify-between gap-4 pt-8 px-8 relative z-10">
                                    <div className="flex items-center gap-4">
                                      <div className={`w-14 h-14 rounded-[1.2rem] shadow-inner text-3xl border-2 leading-none flex items-center justify-center transition-all flex-shrink-0 ${habit.isCompletedToday ? 'bg-[#3a5a40]/20 border-[#3a5a40]/30 grayscale-[50%]' : 'bg-[#dad7cd]/40 dark:bg-[#283618] border-white dark:border-[#3a5a40]/20'}`}>{habit.icon}</div>
                                      <span className={`font-black text-2xl tracking-tighter leading-[1.1] transition-all ${habit.isCompletedToday ? 'text-[#3a5a40]/60 line-through' : 'text-[#344e41] dark:text-[#dad7cd]'}`}>{habit.name}</span>
                                    </div>
                                    <div onClick={() => triggerConfettiAndToggle(habit.id, habit.isCompletedToday)} className={`w-14 h-14 rounded-[1.2rem] border-4 flex items-center justify-center transition-all cursor-pointer flex-shrink-0 z-20 ${habit.isCompletedToday ? 'bg-[#3a5a40] border-[#3a5a40] text-white shadow-lg' : 'border-[#dad7cd] dark:border-[#3a5a40]/40 bg-white/50 dark:bg-black/20 hover:bg-[#3a5a40]/10 hover:border-[#3a5a40]/50'}`}>{habit.isCompletedToday && <CheckCircle2 className="w-8 h-8" />}</div>
                                  </div>
                                  <div className="pt-6 px-8 pb-8 border-t-2 border-[#3a5a40]/10 dark:border-[#3a5a40]/20 relative z-10 bg-white/40 dark:bg-black/20">
                                    <HabitHeatmap logs={habit.logs} />
                                    <div className="flex justify-between items-center mt-6">
                                      <span className="text-[13px] font-black text-[#3a5a40] dark:text-[#a3b18a] flex items-center gap-1.5 uppercase tracking-widest px-4 py-2 bg-white dark:bg-[#283618] border border-[#3a5a40]/10 rounded-xl shadow-sm"> <Flame className="w-4 h-4 text-[#a47148]" /> {habit.streak} D. </span>
                                      <button onClick={() => deleteHabit(habit.id)} className="text-red-400 bg-red-50/50 dark:bg-red-900/10 hover:bg-red-100 hover:text-red-600 dark:hover:bg-red-900/30 transition-all p-2.5 rounded-xl block sm:opacity-0 sm:group-hover:opacity-100 border border-transparent shadow-sm hover:shadow-md"> <Trash2 className="w-5 h-5"/> </button>
                                    </div>
                                  </div>
                                </CardContent>
                              </Card>
                            </motion.div>
                          ))}
                       </div>
                    )}

                    <div className="flex flex-col gap-16 pt-16 border-t-4 border-[#3a5a40]/10">
                       <h3 className="text-4xl font-black text-[#283618] dark:text-[#fefae0] tracking-tighter flex items-center gap-4 uppercase">
                          <Activity className="w-10 h-10 text-[#3a5a40]" /> Estadísticas Anuales
                       </h3>
                       <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
                          <GlobalHeatmap />
                          <MoodHeatmap />
                       </div>
                    </div>
                 </div>
              )}

              {/* BRAIN DUMP */}
              {activeTab === 'brain' && (
                 <div>
                    <h2 className="text-5xl font-black text-[#283618] dark:text-[#fefae0] mb-14 tracking-tighter uppercase">Diario Interno</h2>
                    <BrainDump />
                 </div>
              )}

              {/* ESTADÍSTICAS */}
              {activeTab === 'analytics' && (
                 <div className="flex flex-col gap-16">
                    <h2 className="text-5xl font-black text-[#283618] dark:text-[#fefae0] mb-10 tracking-tighter uppercase">Evolución</h2>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-12 mb-8">
                       <Card className="card-base text-center border-b-[8px]">
                          <p className="text-[13px] font-black text-[#3a5a40] uppercase tracking-[0.3em] mb-4 opacity-50">Hábitos</p>
                          <h4 className="text-7xl font-black text-[#283618] dark:text-[#dad7cd] font-heading">{habits.length}</h4>
                       </Card>
                       <Card className="card-base text-center border-b-[8px] border-[#a47148]/20">
                          <p className="text-[13px] font-black text-[#a47148] uppercase tracking-[0.3em] mb-4 opacity-50">Días Registrados</p>
                          <h4 className="text-7xl font-black text-[#283618] dark:text-[#dad7cd] font-heading">{habitLogs.length}</h4>
                       </Card>
                       <Card className="card-base text-center border-b-[8px] border-[#588157]/20">
                          <p className="text-[13px] font-black text-[#588157] uppercase tracking-[0.3em] mb-4 opacity-50">Notas</p>
                          <h4 className="text-7xl font-black text-[#283618] dark:text-[#dad7cd] font-heading">{useStore.getState().notes.length}</h4>
                       </Card>
                    </div>
                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-16">
                       <AnalyticsDashboard />
                       <div className="card-base flex flex-col items-center justify-center text-center gap-14 bg-[#3a5a40]/5">
                           <div className="w-36 h-36 bg-[#3a5a40]/15 rounded-full flex items-center justify-center text-[#3a5a40] shadow-inner"> <Clock className="w-20 h-20" /> </div>
                           <div className="space-y-6">
                              <h4 className="text-4xl font-black text-[#283618] dark:text-[#dad7cd] tracking-tighter uppercase leading-none">Ritmos Naturales</h4>
                              <p className="text-[#3a5a40] font-bold max-w-sm italic opacity-80 text-2xl leading-tight">"La disciplina es el puente entre tus metas y tus logros cultivados día a día."</p>
                           </div>
                       </div>
                    </div>
                 </div>
              )}

            </motion.div>
          )}
        </AnimatePresence>

      </motion.div>

      {/* DIALOG DE PROGRAMACIÓN */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="rounded-[3rem] border-0 shadow-5xl bg-white dark:bg-[#0a110a] p-16 max-w-3xl overflow-hidden">
          <DialogHeader className="mb-14 space-y-5">
            <DialogTitle className="text-7xl font-black text-[#344e41] dark:text-[#dad7cd] tracking-tighter flex items-center gap-7 uppercase leading-none">
              <div className="p-6 bg-[#3a5a40] rounded-[2rem] shadow-4xl text-white"> <CalendarDays className="w-14 h-14" /> </div>
              Programar
            </DialogTitle>
            <DialogDescription className="font-black text-[#a47148] text-3xl flex items-center gap-5 uppercase bg-[#a47148]/5 p-4 rounded-xl w-fit">
               {format(selectedDateStr ? new Date(selectedDateStr) : new Date(), 'dd MMMM, yyyy')}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-12">
            <div className="space-y-6">
               <label className="text-sm font-black uppercase tracking-[0.4em] text-[#3a5a40] ml-6 opacity-60">Evento o Compromiso</label>
               <Input 
                 placeholder="Ej. Sesión de Enfoque" 
                 value={newEventTitle} 
                 onChange={(e) => setNewEventTitle(e.target.value)} 
                 className="input-base text-5xl h-32 px-12" 
                 autoFocus 
               />
            </div>
          </div>
          <DialogFooter className="mt-20 gap-8 flex flex-col sm:flex-row">
            <Button variant="ghost" onClick={() => setIsDialogOpen(false)} className="flex-1 rounded-[2rem] font-black h-24 text-3xl border-4 border-[#3a5a40]/10 hover:bg-red-50 text-red-500 hover:border-red-100 transition-all uppercase">Cancelar</Button>
            <Button onClick={handleSaveEvent} className="btn-primary flex-1 h-24 text-3xl">
              Confirmar
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}

"use client"

import React from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { BarChart, Bar, XAxis, Tooltip, ResponsiveContainer, CartesianGrid, YAxis, Cell } from 'recharts'
import { useStore } from "@/store/useStore"
import { format, subDays } from 'date-fns'
import { Activity, TrendingUp } from 'lucide-react'

export function AnalyticsDashboard() {
  const { habitLogs } = useStore()

  const today = new Date()
  const data = Array.from({ length: 7 }).map((_, i) => {
    const d = subDays(today, 6 - i)
    const dateStr = format(d, 'yyyy-MM-dd')
    const displayStr = format(d, 'EEE')
    const completedThatDay = habitLogs.filter(l => l.completed_date === dateStr).length

    return {
      name: displayStr,
      completados: completedThatDay
    }
  })

  return (
    <Card className="card-base border-t-[8px] flex flex-col h-full overflow-hidden p-0">
