import React from 'react'
import { ActivityCalendar, ThemeInput } from 'react-activity-calendar'
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card"
import { useStore } from "@/store/useStore"
import { format, subDays, eachDayOfInterval } from 'date-fns'
import { useTheme } from 'next-themes'
import { CalendarDays } from 'lucide-react'

export function EventHeatmap() {
  const { events } = useStore()
  const { resolvedTheme } = useTheme()

  // PALETA CLAY / TIERRA (V5.2)
  const eventTheme: ThemeInput = {
    light: ['#f2e9e4', '#dad7cd', '#a47148', '#8b5e34', '#5c3d2e'],
    dark: ['#1b221b', '#3d2b1f', '#8b5e34', '#a47148', '#dad7cd']
  }

  const data = React.useMemo(() => {
    const today = new Date();
    const startDate = subDays(today, 365);

    const counts: Record<string, number> = {};
    events.forEach(ev => {
      const d = ev.date;
      counts[d] = (counts[d] || 0) + 1;
    });

    const days = eachDayOfInterval({ start: startDate, end: today });
    return days.map(d => {
       const dateStr = format(d, 'yyyy-MM-dd');
       const count = counts[dateStr] || 0;

       let level = 0;
       if (count === 1) level = 1;
       else if (count === 2) level = 2;
       else if (count === 3) level = 3;
       else if (count >= 4) level = 4;

       return {
         date: dateStr,
         count: count,
         level: level as 0 | 1 | 2 | 3 | 4
       }
    })
  }, [events])

  return (
    <Card className="card-base border-t-[8px] border-t-[#a47148]/20">
      <CardHeader className="border-b-2 border-[#a47148]/10 px-12 py-8">
        <CardTitle className="text-3xl text-[#344e41] dark:text-[#dad7cd] font-black flex items-center gap-4 tracking-tighter uppercase leading-none">
           <CalendarDays className="w-8 h-8 text-[#a47148]" /> Historial Anual
        </CardTitle>
      </CardHeader>
      <CardContent className="p-12 overflow-x-auto">
         <div className="min-w-[800px] flex justify-center">
            <ActivityCalendar 
              data={data as any} 
              theme={eventTheme}
              colorScheme={resolvedTheme === 'dark' ? 'dark' : 'light'}
              labels={{
                totalCount: "{{count}} eventos programados en el último año"
              }}
              showWeekdayLabels
              blockSize={20}
              blockMargin={5}
              blockRadius={6}
            />
         </div>
      </CardContent>
    </Card>
  )
}

